SourceCode.Declaration:
/// <summary>
/// Product variant import
/// </summary>
public class ETG_Acu_EcoResReleasedProdVariantImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResReleasedProdVariantImport  releasedProdVariantImport;

    releasedProdVariantImport = ETG_Acu_EcoResReleasedProdVariantImport::construct();

    if (releasedProdVariantImport.prompt())
    {
        releasedProdVariantImport.runOperation();
    }
}

public static ETG_Acu_EcoResReleasedProdVariantImport construct()
{
    return new ETG_Acu_EcoResReleasedProdVariantImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResReleasedProductVariantV2Entity        releasedProdVariant;
    EcoResProductDisplayProductNumber           prodNum;
    EcoResConfigurationName                     configId;
    EcoResSizeName                              sizeId;
    EcoResColorName                             colorId;
    EcoResStyleName                             styleId;

    prodNum     = conpeek(_con, 1);
    configId    = conpeek(_con, 2);
    sizeId      = conpeek(_con, 3);
    colorId     = conpeek(_con, 4);
    styleId     = conpeek(_con, 5);

    select firstonly releasedProdVariant
        where releasedProdVariant.ProductMasterNumber       == prodNum
            && releasedProdVariant.ProductConfigurationId   == configId
            && releasedProdVariant.ProductSizeId            == sizeId
            && releasedProdVariant.ProductColorId           == colorId
            && releasedProdVariant.ProductStyleId           == styleId;

    if (!releasedProdVariant)
    {
        releasedProdVariant.ProductMasterNumber     = prodNum;
        releasedProdVariant.ProductConfigurationId  = configId;
        releasedProdVariant.ProductSizeId           = sizeId;
        releasedProdVariant.ProductColorId          = colorId;
        releasedProdVariant.ProductStyleId          = styleId;
        releasedProdVariant.ItemNumber              = conpeek(_con, 6);
        releasedProdVariant.ProductDescription      = conpeek(_con, 7);
        releasedProdVariant.ProductName             = conpeek(_con, 8);
        releasedProdVariant.ProductSearchName       = conpeek(_con, 9);
        releasedProdVariant.insert();
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpProdVariant";

    return ret;
}
